mapper.select:
SELECT Cookie, Source, AreaMask, DescString, PV, TripValue, DATE_FORMAT(TimeACT, '%Y-%m-%d %H:%i:%s') AS TimeACT, DATE_FORMAT(TimeRTN, '%Y-%m-%d %H:%i:%s') AS TimeRTN, DATE_FORMAT(TimeACK, '%Y-%m-%d %H:%i:%s') AS TimeACK FROM se WHERE TimeACT BETWEEN #{from} AND #{to}
AND AreaMask = #{areaMask}
ORDER BY TimeACT DESC LIMIT 2000
